def sum_digits(n):
    s = 0
    while n:
        s += n % 10
        n //= 10
    return s

def find_min_x(n, s):
    low = 1
    high = n
    answer = n + 1  # Default to no solution
    while low <= high:
        mid = (low + high) // 2
        if mid - sum_digits(mid) >= s:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    return answer

n, s = map(int, input().split())
min_x = find_min_x(n, s)
if min_x <= n:
    print(n - min_x + 1)
else:
    print(0)
